from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character into a fluent sentence.
    """
    if not triples:
        return ""

    # Helper to turn a single triple into a phrase
    def _make_phrase(s: str, pred: str, o: str) -> str:
        o = o.strip('"\'')
        pred = pred.lower()

        def _singular(val: str) -> str:
            if val.endswith('s') and not val.endswith('ss') and ' ' not in val:
                return val[:-1]
            return val

        if pred == "alternativename":
            return f"{s} is also known as {o}"
        elif pred == "creator":
            return f"{s} was created by {o}"
        elif pred == "fullname":
            return f"{s}'s full name is {o}"
        elif pred == "foundedby":
            return f"{s} was founded by {o}"
        elif pred == "keyperson":
            return f"{o} is a key person at {s}"
        elif pred == "city":
            return f"{s} is located in {o}"
        elif pred == "product":
            return f"{s} produces {o}"
        elif pred == "lastaired":
            return f"The last episode of {s} aired on {o}"
        elif pred == "starring":
            return f"{s} stars {o}"
        elif pred == "firstappearanceinfilm":
            return f"{s} first appeared in the film {o}"
        elif pred == "voice":
            return f"{o} provides the voice for {s}"
        elif pred == "distributor":
            return f"{o} distributed {s}"
        elif pred == "birthplace":
            return f"{s} was born in {o}"
        elif pred == "nationality":
            return f"{s} is {_singular(o)}"
        elif pred == "award":
            return f"{s} received the {o}"
        elif pred == "broadcastedby":
            return f"{s} was broadcasted by {o}"
        elif pred == "firstaired":
            return f"{s} first aired on {o}"
        elif pred == "series":
            return f"{s} is part of the series {o}"
        elif pred == "child":
            return f"{s} has a child named {o}"
        else:
            return f"{s} {pred} {o}"

    # Group phrases by their subject to create smoother clauses
    subject_map: dict[str, list[str]] = {}
    for triple in triples:
        phrase = _make_phrase(triple.subject, triple.predicate, triple.object)
        subject_map.setdefault(triple.subject, []).append(phrase)

    # Combine phrases that share the same subject
    combined_clauses: list[str] = []
    for subj, phrases in subject_map.items():
        if len(phrases) == 1:
            combined_clauses.append(phrases[0])
        else:
            # Join multiple predicates for the same subject with commas and 'and' before the last
            clause = ', '.join(phrases[:-1]) + f', and {phrases[-1]}'
            combined_clauses.append(clause)

    # Assemble the final sentence from the subject clauses
    if not combined_clauses:
        return ""
    if len(combined_clauses) == 1:
        sentence = combined_clauses[0]
    else:
        sentence = ', '.join(combined_clauses[:-1]) + f', and {combined_clauses[-1]}'
    if not sentence.endswith('.'):
        sentence += '.'
    return sentence

# EVOLVE-BLOCK-END
